#nullable enable // autogenerated

using System.Collections.Generic;

using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Detections;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Detections;
using MVZ2.Vanilla.Entities;

using MVZ2Logic.Entities;
using MVZ2Logic.Level;

using PVZEngine;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Effects
{
    [AutoEntityBehaviourDefinition(VanillaEffectNames.megaGlowingLaser)]
    public class MegaGlowingLaser : EntityBehaviourDefinition
    {
        public MegaGlowingLaser(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            entity.PlaySound(VanillaSoundID.scifiLaser);
            detectBuffer.Clear();
            laserDetector.DetectEntities(entity, detectBuffer);
            var duration = Ticks.FromSeconds(GLOWING_DURATION_SECONDS);
            var damage = entity.GetDamage();
            foreach (var target in detectBuffer)
            {
                target.InflictGlowing(duration, new EntitySourceReference(entity));
                if (damage > 0)
                {
                    target.TakeDamage(damage, new DamageEffectList(VanillaDamageEffects.LIGHT, VanillaDamageEffects.MUTE, VanillaDamageEffects.DAMAGE_BODY_AFTER_ARMOR_BROKEN), entity);
                }
            }

        }
        public const float GLOWING_DURATION_SECONDS = 30f;
        public static Detector laserDetector = new CollisionDetector(true);
        public List<Entity> detectBuffer = new List<Entity>();
    }
}
